QueryExtension.Constraint:
(
	(
		${param.code} IS NULL OR CT.CODE = ${param.code}
	)
	AND																									
	(
		${param.name} IS NULL OR CT.NAME = UPPER(${param.name})
	) 
	AND																									
	(
		${param.id} IS NULL OR CT.ID LIKE ${param.id}
	) 
	AND
	(
		${param.districtregistry} IS NULL OR CT.DISTRICT_REGISTRY = ${param.districtregistry}
	)
	AND
	(
		${param.supsCourtInd} IS NULL OR CT.SUPS_CENTRALISED_FLAG = ${param.supsCourtInd}
	)												
)
